#!/usr/bin/env osascript -l JavaScript

// JXA script to open new Safari windows with profile and URL support.
//
// Usage:
// ./new_window.js [x<count>] || [p<profile>] || [url]
//
// Examples:
// ./new_window.js                  -> Opens 1 new window.
// ./new_window.js example.com      -> Opens 1 new window with URL.
// ./new_window.js x3               -> Opens 3 new windows.
// ./new_window.js p2               -> Opens 1 new window in profile 2.

/**
 * Parses script arguments to determine window count, profile, or URL.
 * @param {string[]} argv - The script arguments.
 * @returns {{windowCount: number, profile: string|null, url: string|null}}
 */
function parseArgs(argv) {
	const config = {
		windowCount: 1,
		profile: null,
		url: null,
	};

	if (!argv || argv.length === 0) {
		return config;
	}

	const firstArg = argv[0];

	if (/^x[0-9]+$/.test(firstArg)) {
		// Parse window count (e.g., "x3"), capped at 10.
		const count = parseInt(firstArg.substring(1), 10);
		config.windowCount = Math.max(1, Math.min(count, 10));
	} else if (/^p[1-5]$/.test(firstArg)) {
		// Parse profile (e.g., "p2")
		config.profile = firstArg.substring(1);
	} else {
		// The rest is the URL
		const rawUrl = argv.join(" ");
		// Basic validation and formatting
		if (!rawUrl.includes(" ") && rawUrl.includes(".")) {
			if (!/^(https?:\/\/)/i.test(rawUrl)) {
				config.url = "http://" + rawUrl;
			} else {
				config.url = rawUrl;
			}
		}
	}

	return config;
}

function run(argv) {
	"use strict";

	// Initialize applications
	const Safari = Application("Safari");
	const SystemEvents = Application("System Events");
	Safari.includeStandardAdditions = true;

	// --- Argument Parsing ---
	const { windowCount, profile, url } = parseArgs(argv);

	// --- Safari Automation ---

	const safariWasRunning = Safari.running();

	// Ensure Safari is running and activate it
	if (!safariWasRunning) {
		Safari.activate(); // This will open one window
		delay(0.5);
	} else {
		Safari.activate();
	}

	const openInProfile = (p) => {
		// Use keyboard shortcut to switch to the selected profile
		// Option + Shift + Command + n
		SystemEvents.keystroke(p, {
			using: ["option down", "shift down", "command down"],
		});
		delay(0.5); // Wait for the new window to appear
	};

	const openStandardWindow = (u) => {
		const doc = Safari.Document().make();
		if (u) {
			doc.url = u;
		}
	};

	// --- Main Logic ---

	let windowsToCreate = windowCount;

	// If Safari wasn't running, it was just launched, creating one window.
	if (!safariWasRunning) {
		if (profile) {
			// The auto-opened window is in the default profile. Close it.
			try {
				Safari.windows[0].close();
				delay(0.2);
			} catch (e) {
				/* Ignore */
			}
		} else {
			// One window is already open. Set its URL if provided.
			if (url) {
				try {
					Safari.windows[0].currentTab.url = url;
				} catch (e) {
					/* Ignore */
				}
			}
			windowsToCreate--; // Account for the already-opened window.
		}
	}

	// Create the required number of windows.
	for (let i = 0; i < windowsToCreate; i++) {
		if (profile) {
			openInProfile(profile);
		} else {
			openStandardWindow(url);
		}
		// Small delay between multiple windows
		if (windowsToCreate > 1 && i < windowsToCreate - 1) {
			delay(0.2);
		}
	}
}

#!/usr/bin/env osascript -l JavaScript

/**
 * Opens new safari private windows with optional URL.
 *
 * Usage:
 * ./new_private_window.js [url]
 *
 * Examples:
 * ./new_private_window.js          -> Opens 1 new private window.
 * ./new_private_window.js google.com -> Opens 1 new private window with URL.
 */

/**
 * Parses and validates a URL from script arguments.
 * @param {string[]} argv - The script arguments.
 * @returns {string|null} The formatted URL or null if invalid.
 */
function parseUrl(argv) {
	if (!argv || argv.length === 0) {
		return null;
	}

	const rawUrl = argv.join(" ");

	// Basic validation: reject multi-word inputs, require a dot for it to be a URL.
	if (rawUrl.includes(" ") || !rawUrl.includes(".")) {
		return null;
	}

	// Add http protocol if it's missing.
	if (!/^(https?:\/\/)/i.test(rawUrl)) {
		return "http://" + rawUrl;
	}

	return rawUrl;
}

function run(argv) {
	"use strict";

	const url = parseUrl(argv);

	const safari = Application("Safari");
	safari.includeStandardAdditions = true;

	const safariWasRunning = safari.running();
	safari.activate();

	// If Safari wasn't running, it opens a new window by default. Close it.
	if (!safariWasRunning && safari.windows.length > 0) {
		// A small delay might be needed for the window to be ready to close.
		delay(0.1);
		safari.windows[0].close();
	}

	const sysEvents = Application("System Events");
	sysEvents.keystroke("n", { using: ["command down", "shift down"] });

	if (url) {
		delay(0.5);
		safari.windows[0].currentTab.url = url;
	}
}

function run(argv) {
    const query = argv[0];

    const createLink = (title, url) => `[${title}](${url})`;
    const createListItem = (title, url) => `- ${createLink(title, url)}`;

    const processItems = (items) => {
        if (!Array.isArray(items)) return null;
        const links = items
            .filter(item => item.url && item.title)
            .map(item => createListItem(item.title, item.url));
        return links.length > 0 ? links.join('\n') : null;
    };

    try {
        const data = JSON.parse(query);

        if (data.url && data.title) {
            return createLink(data.title, data.url);
        }

        if (Array.isArray(data)) {
            return processItems(data) || query;
        }

        if (data.items && Array.isArray(data.items)) {
            return processItems(data.items) || query;
        }

        return query;
    } catch {
        if (query.includes('=') && query.includes(';')) {
            const titleMatch = query.match(/title\s*=\s*"([^"]+)"/);
            const urlMatch = query.match(/url\s*=\s*"([^"]+)"/);

            if (titleMatch && urlMatch) {
                const title = titleMatch[1].replace(/\\U([0-9A-Fa-f]{4})/g,
                    (_, code) => String.fromCharCode(parseInt(code, 16)));
                return createLink(title, urlMatch[1]);
            }
        }

    }
}

/**
 * Executes a command and returns its standard output.
 * @param {...string} args The command and its arguments to execute.
 * @returns {string} The standard output (stdout) of the command as a string.
 */
function runCommand(...args) {
	const task = $.NSTask.alloc.init;
	const stdout = $.NSPipe.pipe;

	task.executableURL = $.NSURL.fileURLWithPath("/usr/bin/env");
	task.arguments = args;
	task.standardOutput = stdout;
	task.launchAndReturnError(false);

	const dataOut =
		stdout.fileHandleForReading.readDataToEndOfFileAndReturnError(false);
	const stringOut = $.NSString.alloc.initWithDataEncoding(
		dataOut,
		$.NSUTF8StringEncoding
	).js;

	return stringOut;
}

// --- Script Main ---

let output;

try {
	const browserRaw = runCommand(
		$(
			"~/Library/Application Support/Alfred/Automation/Tasks/com.alfredapp.automation.core/safari/.common/tabs"
		).stringByExpandingTildeInPath.js,
		"Safari",
		"1",
		"0",
		"json"
	);

	// The command returns a JSON string where the actual tab data is itself a stringified JSON array.
	// Therefore, we need to parse it twice.
	const browserParsed = JSON.parse(
		JSON.parse(browserRaw)["alfredworkflow"]["arg"]
	);

	if (!browserParsed || browserParsed.length === 0) {
		output = {
			items: [
				{
					title: "No tabs found",
					subtitle: "No open tabs in Safari",
					valid: false,
				},
			],
		};
	} else {
		const uniqueTabs = new Map();

		for (const item of browserParsed) {
			const url = item.url || "";
			if (!url) continue;

			if (uniqueTabs.has(url)) {
				uniqueTabs.get(url).count++;
			} else {
				const title = item.title || "Untitled";
				uniqueTabs.set(url, {
					item: {
						title: title,
						subtitle: url,
						autocomplete: title,
						match: `${title} ${url}`,
						arg: url,
						valid: true,
						quicklookurl: url,
						mods: {
							cmd: {
								subtitle: "⌘ Copy URL to clipboard",
							},
							alt: {
								subtitle: "⌥ Edit URL",
							},
							ctrl: {
								subtitle: "⌃ Close all tabs with this URL",
							},
							"cmd+shift": {
								subtitle: "⇧⌘ Copy markdown URL to clipboard",
								arg: JSON.stringify({ url: url, title: title }),
							},
						},
					},
					count: 1,
				});
			}
		}

		const sfItems = Array.from(uniqueTabs.values()).map((entry) => {
			if (entry.count > 1) {
				entry.item.title += ` · (${entry.count} tabs)`;
			}
			return entry.item;
		});

		output = {
			cache: { seconds: 5, loosereload: true },
			items: sfItems,
		};
	}
} catch (e) {
	let items;
	if (e.message.includes("Unexpected EOF")) {
		items = [
			{
				title: "No Safari tabs found",
				subtitle:
					"Press ↩ to open a new Safari window or Esc to cancel",
				valid: true,
				arg: "1",
				mods: {
					cmd: {
						valid: false,
						subtitle: "These actions require a selected tab",
					},
					ctrl: {
						valid: false,
						subtitle: "These actions require a selected tab",
					},
				},
			},
		];
	} else {
		items = [
			{
				title: "Error getting Safari tabs",
				subtitle: e.message,
				valid: false,
			},
		];
	}
	output = { items };
}

JSON.stringify(output);

#!/usr/bin/env osascript -l JavaScript

/**
 * Focuses a Safari tab by URL or opens it in a new tab if not found
 */
function run(argv) {
    const targetUrl = argv[0];

    try {
        const safari = Application("Safari");
        const windows = safari.windows();

        for (let i = 0; i < windows.length; i++) {
            const window = windows[i];

            try {
                const matchingTabs = window.tabs.whose({ url: targetUrl })();

                if (matchingTabs.length > 0) {
                    window.currentTab = matchingTabs[0];
                    safari.activate();
                    window.index = 1;
                    return "Tab focused successfully";
                }
            } catch (e) {
                continue;
            }
        }

        return "URL not found in open tabs";
    } catch (e) {
        return `Error: ${e.message}`;
    }
}

#!/usr/bin/env osascript -l JavaScript

/**
 * Closes all Safari tabs matching a given URL
 */
function run(argv) {
	if (!argv?.[0]) {
		return "Error: No URL was provided.";
	}
	const targetUrl = argv[0];

	try {
		const safari = Application("Safari");
		const allWindows = safari.windows();

		let closedCount = 0;

		for (let i = 0; i < allWindows.length; i++) {
			const window = allWindows[i];

			try {
				const matchingTabs = window.tabs.whose({ url: targetUrl })();

				// Close all matching tabs in reverse order
				for (let j = matchingTabs.length - 1; j >= 0; j--) {
					try {
						matchingTabs[j].close();
						closedCount++;
					} catch (e) {
						continue;
					}
				}
			} catch (e) {
				continue;
			}
		}

		if (closedCount > 0) {
			return `Successfully closed ${closedCount} tab${
				closedCount > 1 ? "s" : ""
			}.`;
		} else {
			return "No tabs found with the provided URL.";
		}
	} catch (e) {
		return `An error occurred: ${e.message}`;
	}
}
